const Redis = require('ioredis');
const { S3Client, DeleteObjectCommand } = require('@aws-sdk/client-s3');

const photoId = $input.first().json.query?.photoId || $input.first().json.body?.photoId;

if (!photoId) {
  return [{ json: { success: false, error: 'photoId required' } }];
}

const redis = new Redis({ host: 'redis', port: 6379 });

try {
  const photo = await redis.hgetall(`photo:${photoId}`);
  if (!photo || !photo.patientId) {
    await redis.quit();
    return [{ json: { success: false, error: 'Photo not found' } }];
  }

  const s3 = new S3Client({
    region: 'auto',
    endpoint: `https://${process.env.R2_ACCOUNT_ID}.r2.cloudflarestorage.com`,
    credentials: {
      accessKeyId: process.env.R2_ACCESS_KEY_ID,
      secretAccessKey: process.env.R2_SECRET_ACCESS_KEY
    }
  });

  await s3.send(new DeleteObjectCommand({
    Bucket: process.env.R2_BUCKET_NAME,
    Key: photo.r2Key
  }));

  await redis.lrem(`patient:${photo.patientId}:photos`, 0, photoId);
  await redis.del(`photo:${photoId}`);

  await redis.quit();
  return [{ json: { success: true, deletedPhotoId: photoId } }];
} catch (err) {
  await redis.quit().catch(() => {});
  throw err;
}
